#!/usr/bin/env python3
from pathlib import Path
import base64, lzma, subprocess, tempfile

PAYLOAD = """"""
patch = lzma.decompress(base64.b64decode(PAYLOAD))
with tempfile.NamedTemporaryFile(suffix=".patch", delete=False) as handle:
    handle.write(patch)
    patch_path = handle.name
try:
    subprocess.run(["git", "apply", "--whitespace=fix", patch_path], check=True)
finally:
    Path(patch_path).unlink(missing_ok=True)
